org.machanism.macha.core.commons.configurator.Configurator conf = new org.machanism.macha.core.commons.configurator.Configurator();
conf.set("OPENAI_API_KEY", java.lang.System.getenv("OPENAI_API_KEY"));
org.machanism.machai.ai.provider.Genai provider = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4.1", conf);
provider.setWorkingDir(new java.io.File("."));
provider.addTool("echo_message", "Returns the provided message", (com.fasterxml.jackson.databind.JsonNode params, java.io.File projectDir) -> {
  return params != null && params.has("message") ? params.get("message").asText() : "";
}, "message:string:required:Message to echo back");
provider.instructions("Use tools when useful.");
provider.prompt("Call echo_message with message Hello from the tool system.");
java.lang.String result = provider.perform();

